{"orthogonal_sources": [
    {
      "source_name": "Reframe meta-cognition records",
      "source_path_pattern": "answers/*_meta.json",
      "data_type": "json_struct",
      "validity_dimension": "wisdom 是否真正改变了 solver 的问题表征？通过比较 critical_reframe / what_changed 与原题的语义距离，可度量 reframing 深度，排除 wisdom 仅做表面修饰却碰巧赢了 pair-verdict 的情况。",
      "orthogonality_argument": "pair-wr 由 judge 对最终答案质量打分产生；meta 里的 reframe 深度是 solver 内部认知过程的结构化记录，两者噪声源完全不同。"
    },
    {
      "source_name": "Answer-level textual diff",
      "source_path_pattern": "answers/*_answers.json",
      "data_type": "text",
      "validity_dimension": "ext 答案与 base 答案在内容上到底差了多少？若 pair-wr 高但答案文本几乎相同，说明 judge 可能受格式/措辞偏差驱动而非实质改进；反之可确认 wisdom 带来了实质性内容变化。",
      "orthogonality_argument": "pair-wr 是二元胜负信号；答案文本差异是连续语义距离，不经过 judge 评判，噪声来源于文本本身而非 judge 偏好。"
    },
    {
      "source_name": "Wisdom-problem semantic alignment (embedding)",
      "source_path_pattern": "wisdom_library.json + answers/*_meta.json via paraphrase-multilingual-MiniLM-L12-v2",
      "data_type": "embedding",
      "validity_dimension": "被选中的 wisdom 条目与该问题的语义相关度有多高？可检验 wisdom 选择机制是否精准——高 wr 是否伴随高 cosine 相关，还是随机 wisdom 也能赢（即 judge 噪声主导）。",
      "orthogonality_argument": "embedding cosine 是纯几何度量，不依赖 judge 也不依赖答案生成过程，噪声仅来自 embedding 模型表征能力。"
    },
    {
      "source_name": "Anti-pattern structural coverage",
      "source_path_pattern": "answers/*_meta.json (anti_patterns 字段)",
      "data_type": "json_struct",
      "validity_dimension": "solver 识别出的 anti-patterns 是否在 ext 答案中被真正规避？将 anti_patterns 列表与 ext 答案文本做语义匹配，可度量 wisdom 的'纠偏'效果是否落地，而非仅停留在 meta 层。",
      "orthogonality_argument": "anti-pattern 覆盖率是 solver 自省产物与答案文本的交叉检验，不经过外部 judge，噪声来自 solver 自省质量而非评判偏好。"
    },
    {
      "source_name": "Cross-LLM judge divergence",
      "source_path_pattern": "judgments/*.json via LLM judges (Claude Opus 4.6 + GPT-5.4)",
      "data_type": "judge_verdict",
      "validity_dimension": "用第二个 LLM judge 对同一 pair 重新判定，计算 inter-judge agreement (Cohen's κ)。低一致性区域暴露 pair-wr 中 judge 主观偏差最大的题目，为 gate 提供置信度权重。",
      "orthogonality_argument": "两个不同 LLM 的系统性偏差不同，disagreement 信号恰好捕捉原 judge 噪声本身，与 pair-wr 的噪声方向正交。"
    },
    {
      "source_name": "Holdout problem difficulty stratification",
      "source_path_pattern": "autonomous/sample_holdout_50.json",
      "data_type": "json_struct",
      "validity_dimension": "wisdom 增益是否随问题难度/领域变化？将 holdout 的 difficulty 和 domain 标签与 wr 交叉分析，可检测 wisdom 是否仅在特定难度带有效，揭示 gate 的 generalizability 边界。",
      "orthogonality_argument": "difficulty/domain 是问题的先验属性，在答案生成和 judge 评判之前就已确定，与 pair-wr 的运行时噪声无关。"
    }
  ]
}

